import { describe, expect, it, vi, afterAll, beforeAll } from 'vitest';

const { default: ports } = await import('../src/lib/ports.ts');

describe('parsePort regression', () => {
  let saved: Record<string, string | undefined>;

  beforeAll(() => {
    saved = {
      NEMOCLAW_DASHBOARD_PORT: process.env.NEMOCLAW_DASHBOARD_PORT,
    };
  });

  afterAll(() => {
    if (saved.NEMOCLAW_DASHBOARD_PORT === undefined) {
      delete process.env.NEMOCLAW_DASHBOARD_PORT;
    } else {
      process.env.NEMOCLAW_DASHBOARD_PORT = saved.NEMOCLAW_DASHBOARD_PORT;
    }
  });

  it('returns fallback when env var is unset', () => {
    delete process.env.NEMOCLAW_DASHBOARD_PORT;
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(18789);
  });

  it('returns fallback when env var is empty string', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '';
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(18789);
  });

  it('parses a valid port number', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '8080';
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(8080);
  });

  it('parses a valid port with surrounding whitespace', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '  3000  ';
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(3000);
  });

  it('throws on non-integer value', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = 'abc';
    expect(() => ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toThrow(
      /Invalid port.*must be an integer/,
    );
  });

  it('throws on float value', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '3.14';
    expect(() => ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toThrow(
      /Invalid port.*must be an integer/,
    );
  });

  it('throws when port is below 1024', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '80';
    expect(() => ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toThrow(
      /Invalid port.*must be an integer between 1024 and 65535/,
    );
  });

  it('throws when port is above 65535', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '99999';
    expect(() => ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toThrow(
      /Invalid port.*must be an integer between 1024 and 65535/,
    );
  });

  it('succeeds at lower boundary 1024', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '1024';
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(1024);
  });

  it('succeeds at upper boundary 65535', () => {
    process.env.NEMOCLAW_DASHBOARD_PORT = '65535';
    expect(ports.parsePort('NEMOCLAW_DASHBOARD_PORT', 18789)).toBe(65535);
  });
});
